import{_ as i,C as e,c as n,o as h,aB as r,G as a}from"./chunks/framework.Cb2nM6j6.js";const b=JSON.parse('{"title":"ssh 的使用","description":"","frontmatter":{},"headers":[],"relativePath":"views/开发/后端/ssh的使用/index.md","filePath":"views/开发/后端/ssh的使用/index.md","lastUpdated":1762064734000}'),l={name:"views/开发/后端/ssh的使用/index.md"};function d(c,s,m,p,u,_){const o=e("NolebaseGitContributors"),t=e("NolebaseGitChangelog");return h(),n("div",null,[s[0]||(s[0]=r('<h1 id="ssh-的使用" tabindex="-1">ssh 的使用 <a class="header-anchor" href="#ssh-的使用" aria-label="Permalink to &quot;ssh 的使用&quot;">​</a></h1><p>ssh 对于远程开发或者远程部署来讲非常有用，他的使用方法也很简单，以下的案例是在 windwos 的机器上生成 ssh 密钥，然后在 linux 的服务器上使用。</p><h2 id="生成-ssh-密钥" tabindex="-1">生成 ssh 密钥 <a class="header-anchor" href="#生成-ssh-密钥" aria-label="Permalink to &quot;生成 ssh 密钥&quot;">​</a></h2><p>打开 cmd 窗口执行 ssh-keygen -t rsa -b 2048，按照要求填写信息。生成后的 ssh 相关内容一般默认在下面图片的路径中。复制文件里的 ssh 公钥。</p><p><img src="https://jiashu.jsdmirror.com/gh/Ruin-L/image@main/img/20251101132006766.png" alt=""></p><h2 id="将-ssh-公钥添加到-linux-服务器里" tabindex="-1">将 ssh 公钥添加到 linux 服务器里 <a class="header-anchor" href="#将-ssh-公钥添加到-linux-服务器里" aria-label="Permalink to &quot;将 ssh 公钥添加到 linux 服务器里&quot;">​</a></h2><p><img src="https://jiashu.jsdmirror.com/gh/Ruin-L/image@main/img/20251101131908686.png" alt=""></p><h2 id="使用命令远程-ssh" tabindex="-1">使用命令远程 ssh <a class="header-anchor" href="#使用命令远程-ssh" aria-label="Permalink to &quot;使用命令远程 ssh&quot;">​</a></h2><p><code>ssh username@127.0.0.1</code></p><blockquote><p>以上需要替换成 linux 的用户名和服务器 ip 地址，还可以使用<strong>vscode romote ssh</strong>进行远程</p></blockquote><ul><li>[ ] 修改根目录的文件往往需要 root 权限，此时可以使用 vscode 的插件<a href="./">Save as Root in Remote -SSH</a>，具体使用方法参照<a href="./../ssh远程文件修改/">ssh 远程文件修改</a></li></ul>',11)),a(o),a(t)])}const x=i(l,[["render",d]]);export{b as __pageData,x as default};
